SELECT DISTINCT a.*, u.nickname as author_nickname, u.username as author_username FROM article a LEFT JOIN user u ON a.user_id = u.id LEFT JOIN article_content ac ON a.id = ac.article_id
AND (a.title LIKE CONCAT('%', #{keyword}, '%') OR a.category LIKE CONCAT('%', #{keyword}, '%') OR a.tags LIKE CONCAT('%', #{keyword}, '%') OR ac.content LIKE CONCAT('%', #{keyword}, '%'))
AND a.status = #{status}
ORDER BY a.created_at DESC LIMIT #{offset}, #{size}

SELECT COUNT(DISTINCT a.id) FROM article a LEFT JOIN article_content ac ON a.id = ac.article_id
AND (a.title LIKE CONCAT('%', #{keyword}, '%') OR a.category LIKE CONCAT('%', #{keyword}, '%') OR a.tags LIKE CONCAT('%', #{keyword}, '%') OR ac.content LIKE CONCAT('%', #{keyword}, '%'))
AND a.status = #{status}
